//수정 btn
scwin.btn_Update_onclick = function (e) {

    if (ds_consignmentContractDTOList.getRowCount() == 0) {
        $c.gus.cfAlertMsg("수정할 목록이 존재하지 않습니다.");
        return;
    }

    // 확정구분이 미확인(1)이 아닌 상태는 수정불가
    let dcsnClsCd = ds_consignmentManagementCost.getCellData(0, "dcsnClsCd");
    if (dcsnClsCd != "1") {
        $c.gus.cfAlertMsg("상태가 미확인인 경우만 수정가능합니다.");
        return;
    }

    $c.gus.cfEnableBtnOnly([ed_deposit, ed_depositInt, ed_deprCost, udc_bottomGrdBtn, btn_Cancel, btn_Save]);
    gr_consignmentManagementCostDetailList.setDisabled("grid",false);

};

//삭제 btn
scwin.btn_Delete_onclick = async function (e) {

    if (ds_consignmentContractDTOList.getRowCount() == 0) {
        $c.gus.cfAlertMsg("삭제할 목록이 존재하지 않습니다.");
        return;
    }

    // 확정구분이 미확인(1)이 아닌 상태는 삭제불가
    let dcsnClsCd = ds_consignmentManagementCost.getCellData(0, "dcsnClsCd");
    if (dcsnClsCd != "1") {
        $c.gus.cfAlertMsg("상태가 미확인인 경우만 삭제 가능합니다.");
        return;
    }

    let confirm = await $c.win.confirm("삭제하시겠습니까?")
    if( confirm ) {

        if (!$c.gus.cfValidate([ica_ed_ym, ed_deposit, ed_depositInt, ed_deprCost, gr_consignmentManagementCostDetailList])) {
        return;
        }

        scwin.rowPos = ds_consignmentContractDTOList.getRowPosition();  // 저장 전의 위치 저장
        $c.sbm.execute(sbm_save_delete);
    }
};

