    let yyyyMm = ica_ed_ym.getValue();
    let confirm = await $c.win.confirm(yyyyMm.substring(0,4) + "년 " + yyyyMm.substring(4,6) + "월 자료를 EXCEL로 다운로드 받으시겠습니까?");

    if (confirm) {
        dma_consignmentCostQueryConditionDTO.set("ym", ica_ed_ym.getValue());
